mapper.update:
UPDATE t_transport_route
SET deleted_flag = #{deletedFlag}
WHERE transport_route_id = #{transportRouteId}

mapper.select:
SELECT
tr.*
FROM
t_transport_route tr

    tr.deleted_flag = #{queryForm.deletedFlag} AND tr.transport_route_type = #{queryForm.transportRouteType}

        and tr.enterprise_id = #{queryForm.enterpriseId}


        AND (INSTR(tr.transport_route_name,#{queryForm.keywords}) OR INSTR(tr.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(tr.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(tr.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND tr.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY tr.create_time DESC

SELECT tr.*
FROM t_transport_route tr
WHERE tr.transport_route_id = #{transportRouteId}
  AND tr.deleted_flag = #{deletedFlag}

SELECT *
FROM t_transport_route
WHERE deleted_flag = #{deletedFlag} AND disabled_flag = #{disabledFlag}
  and enterprise_id = #{enterpriseId}
order by default_flag desc,transport_route_id desc

SELECT *
FROM t_transport_route
WHERE deleted_flag = #{deletedFlag} AND disabled_flag = #{disabledFlag}
  and enterprise_id = #{enterpriseId}
AND trim(transport_route_name) in

    #{item}
